 21→export type AuthClientErrorCode =
 22→  | "invalid_credentials"
 23→  | "callback_error"
 24→  | "configuration_error"
 25→  | "access_denied"
 26→  | "auth_unavailable"
 27→  | "storage_unavailable"
 28→  | "registration_conflict"
 29→  | "validation_error"
 30→  | "request_error"
 31→  | "unknown_error";
