 33→export class AuthClientError extends Error {
 34→  code: AuthClientErrorCode;
 35→  retryable: boolean;
 36→
 37→  constructor(
 38→    code: AuthClientErrorCode,
 39→    message: string,
 40→    options: { retryable?: boolean; cause?: unknown } = {}
 41→  ) {
 42→    super(message);
 43→    this.name = "AuthClientError";
 44→    this.code = code;
 45→    this.retryable = Boolean(options.retryable);
 46→    if (options.cause !== undefined) {
 47→      (this as Error & { cause?: unknown }).cause = options.cause;
 48→    }
 49→  }
 50→}
