 56→const DEFAULT_SIGN_IN_ERROR = "Unable to sign in. Please try again.";
 57→const DEFAULT_SIGN_OUT_ERROR = "Unable to sign out";
 58→const DEFAULT_SIGN_UP_ERROR = "Unable to create account";
 59→
 60→function delay(ms: number): Promise<void> {
 61→  return new Promise((resolve) => setTimeout(resolve, ms));
 62→}
