 64→function normalizeAttempts(value: number | undefined): number {
 65→  if (!Number.isFinite(value)) return 1;
 66→  return Math.max(1, Math.floor(value as number));
 67→}
 68→
 69→function normalizeDelayMs(value: number | undefined): number {
 70→  if (!Number.isFinite(value)) return 500;
 71→  return Math.max(0, Math.floor(value as number));
 72→}
