 75→async function safeReadJson<T>(response: Response): Promise<T | null> {
 76→  try {
 77→    return (await response.json()) as T;
 78→  } catch {
 79→    return null;
 80→  }
 81→}
 82→
 83→type ApiErrorPayload = {
 84→  message: string;
 85→  code?: string;
 86→};
 87→
 88→async function extractResponseErrorPayload(response: Response, fallback: string): Promise<ApiErrorPayload> {
 89→  const contentType = response.headers.get("content-type")?.toLowerCase() ?? "";
 90→  if (contentType.includes("application/json")) {
 91→    const payload = await safeReadJson<{ error?: unknown; message?: unknown; code?: unknown }>(response);
 92→    if (payload) {
 93→      const message = sanitizeErrorMessage(payload.error ?? payload.message, fallback);
 94→      const code = typeof payload.code === "string" && payload.code.trim() ? payload.code.trim() : undefined;
 95→      return { message, code };
 96→    }
 97→    return { message: fallback };
 98→  }
 99→  const text = await response.text().catch(() => "");
100→  return { message: sanitizeErrorMessage(text, fallback) };
101→}
102→
103→function mapAuthJsError(errorType: string | null, errorCode: string | null): AuthClientError {
104→  switch (errorType) {
105→    case "CredentialsSignin":
106→      return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
107→    case "Callback":
108→    case "CallbackRouteError":
109→      return new AuthClientError("callback_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
110→    case "Configuration":
111→      return new AuthClientError("configuration_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
112→    case "AccessDenied":
113→      return new AuthClientError("access_denied", "Access denied for this account.");
114→    default:
115→      if (errorCode === "credentials") {
116→        return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
117→      }
118→      return new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
119→  }
120→}
121→
122→function toAuthClientError(error: unknown, fallback: string): AuthClientError {
123→  if (error instanceof AuthClientError) return error;
124→  if (error instanceof Error) {
125→    return new AuthClientError("unknown_error", sanitizeErrorMessage(error.message, fallback), { cause: error });
126→  }
127→  return new AuthClientError("unknown_error", fallback);
128→}
