145→async function signInWithCredentialsOnce(identifier: string, password: string): Promise<void> {
146→  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
147→  const csrfToken = await getCsrfToken();
148→  const body = new URLSearchParams();
149→  body.set("csrfToken", csrfToken);
150→  body.set("identifier", normalizedIdentifier);
151→  body.set("email", normalizedIdentifier);
152→  body.set("password", password);
153→  body.set("callbackUrl", window.location.origin);
154→  body.set("json", "true");
155→
156→  const response = await apiFetch("/api/auth/callback/credentials", {
157→    method: "POST",
158→    headers: {
159→      "Content-Type": "application/x-www-form-urlencoded",
160→      "X-Auth-Return-Redirect": "1",
161→    },
162→    body,
163→  });
164→
165→  if (!response.ok) {
166→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_IN_ERROR);
167→    const retryable = response.status >= 500;
168→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
169→  }
170→
171→  const payload = await safeReadJson<AuthRedirectPayload>(response);
172→  if (!payload || typeof payload.url !== "string") {
173→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
174→  }
175→
176→  let url: URL;
177→  try {
178→    url = new URL(payload.url, window.location.origin);
179→  } catch {
180→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
181→  }
182→
183→  const errorType = url.searchParams.get("error");
184→  const errorCode = url.searchParams.get("code");
185→  if (errorType || errorCode) {
186→    throw mapAuthJsError(errorType, errorCode);
187→  }
188→}
