211→export async function signOut(): Promise<void> {
212→  const csrfToken = await getCsrfToken();
213→  const body = new URLSearchParams();
214→  body.set("csrfToken", csrfToken);
215→  body.set("callbackUrl", window.location.origin);
216→  body.set("json", "true");
217→
218→  const response = await apiFetch("/api/auth/signout", {
219→    method: "POST",
220→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
221→    body,
222→  });
223→  if (!response.ok) {
224→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_OUT_ERROR);
225→    const retryable = response.status >= 500;
226→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
227→  }
228→}
