254→export async function signInWithGoogle(): Promise<void> {
255→  const csrfToken = await getCsrfToken();
256→  const form = document.createElement("form");
257→  form.method = "POST";
258→  form.action = buildUrl("/api/auth/signin/google");
259→  form.style.display = "none";
260→
261→  const addField = (name: string, value: string) => {
262→    const input = document.createElement("input");
263→    input.type = "hidden";
264→    input.name = name;
265→    input.value = value;
266→    form.appendChild(input);
267→  };
268→
269→  addField("csrfToken", csrfToken);
270→  addField("callbackUrl", window.location.origin);
271→
272→  document.body.appendChild(form);
273→  form.submit();
274→}
