120→export async function PUT(request: Request): Promise<Response> {
121→  const auth = await requireUser(request);
122→  if (!auth) return errorResponse("Unauthorized", 401);
123→
124→  let body: UpdateUserBody;
125→  try {
126→    body = (await request.json()) as UpdateUserBody;
127→  } catch {
128→    return errorResponse("Invalid JSON body", 400);
129→  }
130→
131→  try {
132→    const profile = await getUserProfile(auth.id);
133→    if (!profile) return errorResponse("Profile not found", 404);
134→
135→    if (body?.occupation !== undefined) {
136→      if (typeof body.occupation !== "string") return errorResponse("Invalid occupation", 400);
137→      const normalized = body.occupation.trim();
138→      if (normalized.length > 120) return errorResponse("Occupation exceeds maximum length", 400);
139→      profile.occupation = normalized;
140→    }
141→
142→    if (body?.mapScope !== undefined) {
143→      const nextScope = normalizeMapScope(body.mapScope);
144→      if (!nextScope) return errorResponse("Invalid mapScope", 400);
145→      if (!profile.isAdmin && nextScope !== "bonamoussadi") {
146→        return errorResponse("Only admin users can unlock map scope", 403);
147→      }
148→      profile.mapScope = nextScope;
149→    }
150→
151→    await upsertUserProfile(auth.id, profile);
152→    return jsonResponse(profile, { status: 200 });
153→  } catch (error) {
154→    if (isStorageUnavailableError(error)) {
155→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
156→    }
157→    throw error;
158→  }
159→}
