194→export async function PATCH(request: Request): Promise<Response> {
195→  const auth = await requireUser(request);
196→  if (!auth) return errorResponse("Unauthorized", 401);
197→  const authIsAdmin = isAdminToken(auth.token);
198→
199→  const url = new URL(request.url);
200→  const view = url.searchParams.get("view");
201→  if (view !== "assignments") return errorResponse("Invalid view", 400);
202→
203→  let body: AssignmentPatchBody;
204→  try {
205→    body = (await request.json()) as AssignmentPatchBody;
206→  } catch {
207→    return errorResponse("Invalid JSON body", 400);
208→  }
209→
210→  const id = typeof body.id === "string" ? body.id.trim() : "";
211→  if (!id) return errorResponse("Assignment id is required", 400);
212→
213→  try {
214→    const existing = await getAssignmentById(id);
215→    if (!existing) return errorResponse("Assignment not found", 404);
216→    if (!authIsAdmin && existing.agentUserId !== auth.id.toLowerCase().trim()) {
217→      return errorResponse("Forbidden", 403);
218→    }
219→    if (!authIsAdmin && body.status === "expired") {
220→      return errorResponse("Only admins can expire assignments", 403);
221→    }
222→    if (!authIsAdmin && existing.status === "completed" && body.status && body.status !== "completed") {
223→      return errorResponse("Completed assignments cannot be reopened", 403);
224→    }
225→
226→    const updated = await updateAssignment(id, {
227→      status: body.status,
228→      pointsSubmitted: authIsAdmin ? body.pointsSubmitted : undefined,
229→      notes: body.notes,
230→    });
231→    if (!updated) return errorResponse("Assignment not found", 404);
232→    return jsonResponse(updated, { status: 200 });
233→  } catch (error) {
234→    if (isStorageUnavailableError(error)) {
235→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
236→    }
237→    const message = error instanceof Error ? error.message : "Unable to update assignment";
238→    return errorResponse(message, 400);
239→  }
